#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k02875Custom {
public:
  __aicore__ inline KernelCa6k02875Custom() {}

  __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                              uint32_t totalLength, uint32_t tileLength,
                              uint32_t numSamples, uint32_t L_in, uint32_t L_out,
                              uint32_t kernel_size, uint32_t stride, uint32_t padding) {
    totalLen_ = totalLength;
    tileLen_ = tileLength;
    numSamples_ = numSamples;
    L_in_ = L_in;
    L_out_ = L_out;
    kernel_size_ = kernel_size;
    stride_ = stride;
    padding_ = padding;
    xGm_.SetGlobalBuffer((__gm__ float*)x, numSamples * L_in);
    yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    // No local buffers needed for scalar implementation
  }

  __aicore__ inline void Process() {
    if (totalLen_ == 0 || tileLen_ == 0) return;

    uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
    uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());

    uint32_t strideElems = blockNum * tileLen_;
    uint32_t base = blockIdx * tileLen_;
    if (base >= totalLen_) return;

    uint32_t curLen = totalLen_ - base;
    if (curLen > tileLen_) curLen = tileLen_;

    // Fence to ensure input is visible
    AscendC::Fence();

    for (uint32_t i = 0; i < curLen; ++i) {
      uint32_t outIdx = base + i;
      uint32_t sampleIdx = outIdx / L_out_;
      uint32_t outWithinSample = outIdx % L_out_;
      int32_t start = static_cast<int32_t>(outWithinSample * stride_) - static_cast<int32_t>(padding_);
      float sum = 0.0f;
      uint32_t count = 0;
      for (uint32_t k = 0; k < kernel_size_; ++k) {
        int32_t idx = start + static_cast<int32_t>(k);
        if (idx >= 0 && static_cast<uint32_t>(idx) < L_in_) {
          sum += xGm_[sampleIdx * L_in_ + static_cast<uint32_t>(idx)];
          ++count;
        }
      }
      yGm_[outIdx] = (count > 0) ? (sum / static_cast<float>(count)) : 0.0f;
    }
  }

private:
  AscendC::GlobalTensor<float> xGm_;
  AscendC::GlobalTensor<float> yGm_;

  uint32_t totalLen_ {0};
  uint32_t tileLen_ {0};
  uint32_t numSamples_ {0};
  uint32_t L_in_ {0};
  uint32_t L_out_ {0};
  uint32_t kernel_size_ {0};
  uint32_t stride_ {0};
  uint32_t padding_ {0};
};

extern "C" __global__ __aicore__ void ca6k_02875_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
  GET_TILING_DATA(td, tiling);
  KernelCa6k02875Custom op;
  op.Init(x, y, td.totalLength, td.tileLength, td.numSamples, td.L_in, td.L_out, td.kernel_size, td.stride, td.padding);
  op.Process();
}
